mapper.insert:

	SELECT SMS_SEQ.NEXTVAL AS mseq
	FROM   DUAL

/* SmsCommonMapper.insertMsgQueue */
INSERT INTO MSG_QUEUE (
	 MSEQ			/* Sequence		*/
	,MSG_TYPE		/* 1:SMS 2:SMS URL 3:MMS 4:MMS URL	*/
	,DSTADDR		/* 수신자 번호	*/
	,CALLBACK		/* 발신자 번호	*/
	,SUBJECT		/* 제목 		*/
	,TEXT			/* 전송메시지	*/
	,EXPIRETIME		/* 유효시간		*/
	,REQUEST_TIME	/* 발송요청시간	*/
	,OPT_ID			/* SMS TEMPLATE ID	*/
)
VALUES (
	 #{mseq}
	,#{msgType}
	,#{mobileNo}
	,#{sendNumber}
	,#{subject}
	,#{sendMessage}
	,#{expireTime}
	,TO_DATE(#{requestTime}, 'YYYYMMDDHH24MISS')
	,#{templateId}
)

/* SmsCommonMapper.insertSmsSendMst */
INSERT INTO MSP_SMS_SEND_MST (
	 SEND_SEQ			/* 일련번호	*/
	,SEND_DIVISION		/* 발송구분(MCP:홈페이지,MSP:M전산) */
	,CONTRACT_NUM		/* 계약번호 */
	,PORTAL_USER_ID		/* 홈페이지사용자ID */
	,MSP_USER_ID		/* M전산(본사)사용자ID */
	,TEMPLATE_ID		/* SMS Template ID */
	,MSEQ				/* SMS일련번호 */
	,SEND_REQ_DTTM		/* 발송요청일시 */
	,REGST_ID			/* 등록자ID */
	,REGST_DTTM			/* 등록일시 */
	,RVISN_ID			/* 수정자ID */
	,RVISN_DTTM			/* 수정일시 */
)
VALUES (
	 SMS_SEND_SEQ.NEXTVAL
	,#{sendDivision}
	,#{contractNum}
	,#{portalUserid}
	,#{mspUserId}
	,#{templateId}
	,#{mseq}
	,#{requestTime}
	,#{reqId}
	,SYSDATE
	,#{reqId}
	,SYSDATE
)

mapper.update:
/* SmsCommonMapper.updateSmsSendMst */
UPDATE  MSP_SMS_SEND_MST
SET     SEND_CNT = SEND_CNT + 1
      , MSEQ = #{mseq}
      , SEND_REQ_DTTM = #{requestTime}
      , RVISN_ID = #{reqId}
      , RVISN_DTTM = SYSDATE
WHERE   SEND_SEQ = #{sendSeq}

mapper.select:
/* SmsMgmtMapper.getTemplateText */
SELECT text AS templateText
	  ,subject AS templateSubject
FROM   MSP_SMS_TEMPLATE_MST
WHERE  TEMPLATE_ID = #{templateId}
